import{_ as t,c as e,o as i,a1 as l}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"快速开始: Antigravity Auth 安装配置 | OpenCode","description":"学习 Antigravity Auth 插件的安装和配置方法。在 10 分钟内完成 Google OAuth 认证，发送第一个模型请求，验证 Claude 和 Gemini 模型访问是否成功。","frontmatter":{"title":"快速开始: Antigravity Auth 安装配置 | OpenCode","sidebarTitle":"10 分钟跑起来","subtitle":"快速开始: Antigravity Auth 安装配置","description":"学习 Antigravity Auth 插件的安装和配置方法。在 10 分钟内完成 Google OAuth 认证，发送第一个模型请求，验证 Claude 和 Gemini 模型访问是否成功。","order":1},"headers":[],"relativePath":"zh/NoeFabris/opencode-antigravity-auth/start/index.md","filePath":"zh/NoeFabris/opencode-antigravity-auth/start/index.md"}'),r={name:"zh/NoeFabris/opencode-antigravity-auth/start/index.md"};function o(n,a,h,u,s,d){return i(),e("div",null,[...a[0]||(a[0]=[l('<h1 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to &quot;快速开始&quot;">​</a></h1><p>本章节帮助你从零开始使用 Antigravity Auth 插件。你将了解插件的核心价值，完成安装和 OAuth 认证，并发送第一个模型请求验证配置是否成功。</p><h2 id="学习路径" tabindex="-1">学习路径 <a class="header-anchor" href="#学习路径" aria-label="Permalink to &quot;学习路径&quot;">​</a></h2><p>按以下顺序学习，每一步都建立在前一步的基础上：</p><h3 id="_1-插件介绍" tabindex="-1">1. <a href="./what-is-antigravity-auth/">插件介绍</a> <a class="header-anchor" href="#_1-插件介绍" aria-label="Permalink to &quot;1. [插件介绍](./what-is-antigravity-auth/)&quot;">​</a></h3><p>了解 Antigravity Auth 插件的核心价值、适用场景和风险提示。</p><ul><li>判断插件是否适合你的使用场景</li><li>了解支持的 AI 模型（Claude Opus 4.5、Sonnet 4.5、Gemini 3 Pro/Flash）</li><li>明确使用风险和注意事项</li></ul><h3 id="_2-快速安装" tabindex="-1">2. <a href="./quick-install/">快速安装</a> <a class="header-anchor" href="#_2-快速安装" aria-label="Permalink to &quot;2. [快速安装](./quick-install/)&quot;">​</a></h3><p>5 分钟快速完成插件安装和首次认证。</p><ul><li>两种安装方式（AI 辅助 / 手动配置）</li><li>配置模型定义</li><li>执行 Google OAuth 认证</li></ul><h3 id="_3-oauth-2-0-pkce-认证" tabindex="-1">3. <a href="./first-auth-login/">OAuth 2.0 PKCE 认证</a> <a class="header-anchor" href="#_3-oauth-2-0-pkce-认证" aria-label="Permalink to &quot;3. [OAuth 2.0 PKCE 认证](./first-auth-login/)&quot;">​</a></h3><p>理解 OAuth 2.0 PKCE 认证流程，完成首次登录。</p><ul><li>理解 PKCE 认证的安全机制</li><li>完成首次登录获取 API 访问权限</li><li>了解令牌刷新的自动化处理</li></ul><h3 id="_4-第一个请求" tabindex="-1">4. <a href="./first-request/">第一个请求</a> <a class="header-anchor" href="#_4-第一个请求" aria-label="Permalink to &quot;4. [第一个请求](./first-request/)&quot;">​</a></h3><p>发起第一个模型请求，验证安装成功。</p><ul><li>发送第一个 Antigravity 模型请求</li><li>理解 <code>--model</code> 和 <code>--variant</code> 参数</li><li>排查常见的模型请求错误</li></ul><h2 id="前置条件" tabindex="-1">前置条件 <a class="header-anchor" href="#前置条件" aria-label="Permalink to &quot;前置条件&quot;">​</a></h2><p>开始本章节前，请确认：</p><ul><li>✅ 已安装 OpenCode CLI（<code>opencode</code> 命令可用）</li><li>✅ 有可用的 Google 账户（用于 OAuth 认证）</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>完成快速开始后，你可以：</p><ul><li><strong><a href="./../platforms/available-models/">了解可用模型</a></strong> — 探索所有支持的模型及其变体配置</li><li><strong><a href="./../advanced/multi-account-setup/">配置多账户</a></strong> — 设置多个 Google 账户实现配额池化</li><li><strong><a href="./../faq/common-auth-issues/">常见认证问题</a></strong> — 遇到问题时查阅故障排除指南</li></ul>',22)])])}const f=t(r,[["render",o]]);export{p as __pageData,f as default};
